class Solution:
    def insert(self, nums):
        nums.append(0)
        for i in range(len(nums) - 1, 0, -1):
            if nums[i] > nums[i - 1]:
                val = nums[i]
                parent = i // 2
                while parent >= 1 and val > nums[parent]:
                    nums[i] = nums[parent]
                    i = parent
                    parent = parent // 2
                nums[i] = val
            else:
                break
        return nums


